title: $:/plugins/rimir/file-pipeline/finalize-route
type: application/javascript
module-type: route

POST /api/file-pipeline-finalize — resize a selected frame to thumbnail,
move to _generated/ folder, and clean up _derived/ frames.

Body: { sourceUri, frameUri }
Response: { thumbnailUri }

\*/
"use strict";

var fs = require("fs");
var path = require("path");
var child_process = require("child_process");

var logger = new $tw.utils.Logger("file-pipeline", {colour: "magenta"});

var uriResolver = null;
try {
	uriResolver = require("$:/plugins/rimir/file-upload/uri-resolver");
} catch(e) {}

exports.method = "POST";
exports.path = /^\/api\/file-pipeline-finalize$/;

exports.handler = function(request, response, state) {
	var data;
	try {
		data = JSON.parse(state.data || "{}");
	} catch(e) {
		sendJson(response, 400, {error: "Invalid JSON body"});
		return;
	}

	var sourceUri = data.sourceUri;
	var frameUri = data.frameUri;

	if(!sourceUri) {
		sendJson(response, 400, {error: "Missing sourceUri"});
		return;
	}

	if(!uriResolver) {
		sendJson(response, 500, {error: "file-upload plugin required"});
		return;
	}

	// Resolve source URI
	var sourceResolved = uriResolver.resolveSecure(sourceUri);
	if(!sourceResolved) {
		sendJson(response, 403, {error: "Cannot resolve source URI"});
		return;
	}

	var sourceParsed = path.parse(sourceResolved.filePath);

	// Helper: clean up _derived/<source-basename>/
	function cleanupDerived() {
		var derivedDir = path.join(sourceParsed.dir, "_derived", sourceParsed.base);
		try {
			if(fs.existsSync(derivedDir)) {
				var files = fs.readdirSync(derivedDir);
				for(var i = 0; i < files.length; i++) {
					fs.unlinkSync(path.join(derivedDir, files[i]));
				}
				fs.rmdirSync(derivedDir);
				var derivedParent = path.join(sourceParsed.dir, "_derived");
				var remaining = fs.readdirSync(derivedParent);
				if(remaining.length === 0) {
					fs.rmdirSync(derivedParent);
				}
			}
		} catch(e) {
			logger.log("Derived cleanup error: " + e.message);
		}
	}

	// No frame selected — cleanup only (cancel/skip)
	if(!frameUri) {
		logger.log("Cleaning up derived frames (cancelled) for " + sourceParsed.base);
		cleanupDerived();
		sendJson(response, 200, {cleaned: true});
		return;
	}

	// Resolve frame URI
	var frameResolved = uriResolver.resolveSecure(frameUri);
	if(!frameResolved) {
		sendJson(response, 403, {error: "Cannot resolve frame URI"});
		return;
	}
	if(!fs.existsSync(frameResolved.filePath)) {
		sendJson(response, 404, {error: "Frame file not found: " + frameUri});
		return;
	}

	// Read thumbnail resolution from config
	var resTiddler = $tw.wiki.getTiddler("$:/config/rimir/file-pipeline/thumb-resolution");
	var resolution = (resTiddler && resTiddler.fields.text || "200").trim();
	if(/^\d+$/.test(resolution)) {
		resolution = resolution + "x" + resolution;
	}

	// Compute output: <source-dir>/_generated/<source-name>_thumb.png
	var generatedDir = path.join(sourceParsed.dir, "_generated");
	$tw.utils.createDirectory(generatedDir);
	var outputPath = path.join(generatedDir, sourceParsed.name + "_thumb.png");

	// Resize frame using ImageMagick. -auto-orient is defensive: ffmpeg autorotate
	// normally strips rotation metadata on extracted frames, but this is a no-op
	// in that case and guards against any edge case that leaves EXIF orientation.
	var command = 'magick "' + frameResolved.filePath + '" -auto-orient -thumbnail "' + resolution + '>" "' + outputPath + '"';
	logger.log("Resizing frame to thumbnail: " + sourceParsed.name + "_thumb.png (" + resolution + ")");

	child_process.exec(command, {
		cwd: $tw.boot.wikiPath,
		timeout: 30000
	}, function(err) {
		if(err) {
			logger.log("Thumbnail resize failed: " + err.message);
			sendJson(response, 500, {error: "Thumbnail resize failed: " + err.message});
			return;
		}
		logger.log("Thumbnail created: " + outputPath);

		// Clean up all extracted frames
		cleanupDerived();
		logger.log("Cleaned up derived frames for " + sourceParsed.base);

		// Build thumbnail URI
		var sourceUriDir = sourceUri.substring(0, sourceUri.lastIndexOf("/"));
		var thumbnailUri = sourceUriDir + "/_generated/" + sourceParsed.name + "_thumb.png";

		sendJson(response, 200, {thumbnailUri: thumbnailUri});
	});
};

function sendJson(response, statusCode, data) {
	var body = JSON.stringify(data);
	response.writeHead(statusCode, {
		"Content-Type": "application/json"
	});
	response.end(body);
}
","type":"application/javascript","module-type":"route"},"$:/plugins/rimir/file-pipeline/handlers-startup":{"title":"$:/plugins/rimir/file-pipeline/handlers-startup","text":"/*\
title: $:/plugins/rimir/file-pipeline/handlers-startup
type: application/javascript
module-type: startup

Registers widget message handlers for pipeline interactive flows:
- tm-fp-use-artifact: completes interactive LLM step (wires up resumeInteractive)
- tm-fp-confirm-select: completes frame/image selection step
- tm-fp-cancel-select: cancels selection without creating artifacts

\*/
"use strict";

exports.name = "file-pipeline-handlers";
exports.platforms = ["browser"];
exports.after = ["startup"];

exports.startup = function() {
	var pipelineClient = require("$:/plugins/rimir/file-pipeline/pipeline-client");

	// --- Interactive LLM step: "Use as Artifact" button ---
	$tw.rootWidget.addEventListener("tm-fp-use-artifact", function(event) {
		var params = event.paramObject || {};
		var sourceTitle = params.sourceTitle;
		var messages = params.messages;
		if(!sourceTitle) return;
		// Extract the last assistant message as the response text
		var responseText = "";
		if(messages) {
			try {
				var parsed = JSON.parse(messages);
				for(var i = parsed.length - 1; i >= 0; i--) {
					if(parsed[i].role === "assistant") {
						responseText = parsed[i].content || "";
						break;
					}
				}
			} catch(e) {
				responseText = messages;
			}
		}
		pipelineClient.resumeInteractive(sourceTitle, responseText);
	});

	// --- Select step: "Confirm" button ---
	$tw.rootWidget.addEventListener("tm-fp-confirm-select", function(event) {
		var params = event.paramObject || {};
		var sourceTitle = params.sourceTitle;
		if(!sourceTitle) return;
		// Read single selected URI from the choice tiddler
		var choiceTiddler = $tw.wiki.getTiddler("$:/temp/rimir/file-pipeline/select-choice");
		var selectedUri = choiceTiddler ? (choiceTiddler.fields.text || "").trim() : "";
		pipelineClient.resumeSelect(sourceTitle, selectedUri);
	});

	// --- Select step: "Cancel" button ---
	$tw.rootWidget.addEventListener("tm-fp-cancel-select", function(event) {
		var params = event.paramObject || {};
		var sourceTitle = params.sourceTitle;
		if(sourceTitle) {
			pipelineClient.cancelSelect(sourceTitle);
		} else {
			// Stale state — just clean up state tiddlers
			$tw.wiki.deleteTiddler("$:/state/rimir/file-pipeline/select");
			$tw.wiki.deleteTiddler("$:/temp/rimir/file-pipeline/select-choice");
		}
	});
};
","type":"application/javascript","module-type":"startup"},"$:/plugins/rimir/file-pipeline/icon":{"title":"$:/plugins/rimir/file-pipeline/icon","type":"image/svg+xml","text":"<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 22 22" width="22pt" height="22pt"><path d="M3 4a1 1 0 0 1 1-1h5l2 2h7a1 1 0 0 1 1 1v2H3V4z" fill="#800020" opacity="0.6"/><path d="M3 8h16v9a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1V8z" fill="none" stroke="#800020" stroke-width="1.2"/><path d="M7 11l2 2 4-4" fill="none" stroke="#800020" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>"},"$:/plugins/rimir/file-pipeline/modules/panel-drag-resize.js":{"title":"$:/plugins/rimir/file-pipeline/modules/panel-drag-resize.js","text":"/*\
title: $:/plugins/rimir/file-pipeline/modules/panel-drag-resize.js
type: application/javascript
module-type: startup

Adds drag-to-move (via header) and edge/corner resize to .fp-select-panel

\*/
(function() {

"use strict";

exports.name = "fp-panel-drag-resize";
exports.platforms = ["browser"];
exports.after = ["render"];

var EDGE = 6;
var MIN_W = 360;
var MIN_H = 250;
var SELECTOR = ".fp-select-panel";
var HEADER_SELECTOR = ".fp-select-header";

exports.startup = function() {
	var state = null;

	document.addEventListener("mousedown", function(e) {
		var panel = findPanel(e.target);
		if(!panel) return;

		// Check if dragging from header (move) or edge (resize)
		var header = e.target.closest(HEADER_SELECTOR);
		if(header && header.closest(SELECTOR) === panel) {
			// Don't capture clicks on buttons inside the header
			if(e.target.closest("button")) return;

			e.preventDefault();
			e.stopImmediatePropagation();
			pinPanel(panel);
			var rect = panel.getBoundingClientRect();
			state = {
				panel: panel,
				mode: "move",
				startX: e.clientX,
				startY: e.clientY,
				startLeft: rect.left,
				startTop: rect.top
			};
			document.body.style.cursor = "grabbing";
			document.body.style.userSelect = "none";
			document.body.style.webkitUserSelect = "none";
			return;
		}

		var zone = hitTest(panel, e.clientX, e.clientY);
		if(!zone) return;

		e.preventDefault();
		e.stopImmediatePropagation();
		pinPanel(panel);
		var rect2 = panel.getBoundingClientRect();
		state = {
			panel: panel,
			mode: "resize",
			zone: zone,
			startX: e.clientX,
			startY: e.clientY,
			startRect: { left: rect2.left, top: rect2.top, width: rect2.width, height: rect2.height }
		};
		document.body.style.cursor = cursorFor(zone);
		document.body.style.userSelect = "none";
		document.body.style.webkitUserSelect = "none";
	}, true);

	document.addEventListener("mousemove", function(e) {
		if(!state) {
			// Hover cursor
			var panel = findPanel(e.target);
			if(panel) {
				var header = e.target.closest(HEADER_SELECTOR);
				if(header && header.closest(SELECTOR) === panel && !e.target.closest("button")) {
					panel.style.cursor = "grab";
				} else {
					var zone = hitTest(panel, e.clientX, e.clientY);
					panel.style.cursor = zone ? cursorFor(zone) : "";
				}
			}
			return;
		}

		e.preventDefault();
		var dx = e.clientX - state.startX;
		var dy = e.clientY - state.startY;
		var p = state.panel;

		if(state.mode === "move") {
			p.style.left = (state.startLeft + dx) + "px";
			p.style.top = (state.startTop + dy) + "px";
			return;
		}

		// Resize
		var s = state.startRect;
		var z = state.zone;
		var newLeft = s.left, newTop = s.top, newW = s.width, newH = s.height;

		if(z.indexOf("w") !== -1) { newW = Math.max(MIN_W, s.width - dx); newLeft = s.left + s.width - newW; }
		if(z.indexOf("e") !== -1) { newW = Math.max(MIN_W, s.width + dx); }
		if(z.indexOf("n") !== -1) { newH = Math.max(MIN_H, s.height - dy); newTop = s.top + s.height - newH; }
		if(z.indexOf("s") !== -1) { newH = Math.max(MIN_H, s.height + dy); }

		p.style.left = newLeft + "px";
		p.style.top = newTop + "px";
		p.style.width = newW + "px";
		p.style.height = newH + "px";
	}, true);

	document.addEventListener("mouseup", function() {
		if(!state) return;
		document.body.style.cursor = "";
		document.body.style.userSelect = "";
		document.body.style.webkitUserSelect = "";
		state = null;
	}, true);
};

function findPanel(el) {
	return el.closest ? el.closest(SELECTOR) : null;
}

function pinPanel(panel) {
	var rect = panel.getBoundingClientRect();
	panel.style.left = rect.left + "px";
	panel.style.top = rect.top + "px";
	panel.style.right = "auto";
	panel.style.bottom = "auto";
	panel.style.transform = "none";
	panel.style.width = rect.width + "px";
	panel.style.height = rect.height + "px";
	panel.style.maxHeight = "none";
}

function hitTest(panel, cx, cy) {
	var r = panel.getBoundingClientRect();
	var inLeft = cx - r.left < EDGE;
	var inRight = r.right - cx < EDGE;
	var inTop = cy - r.top < EDGE;
	var inBottom = r.bottom - cy < EDGE;
	if(!inLeft && !inRight && !inTop && !inBottom) return null;
	var zone = "";
	if(inTop) zone += "n";
	if(inBottom) zone += "s";
	if(inLeft) zone += "w";
	if(inRight) zone += "e";
	return zone || null;
}

function cursorFor(zone) {
	var map = { n:"n-resize", s:"s-resize", w:"w-resize", e:"e-resize", nw:"nw-resize", ne:"ne-resize", sw:"sw-resize", se:"se-resize" };
	return map[zone] || "default";
}

