title: $:/plugins/rimir/file-pipeline/pipeline-client
type: application/javascript
module-type: library

Browser-side pipeline client. Triggers pipeline execution on the server,
creates artifact tiddlers from results, and handles LLM steps (auto + interactive).

\*/
"use strict";

var STATUS_PREFIX = "$:/temp/rimir/file-pipeline/status/";
var PENDING_PREFIX = "$:/temp/rimir/file-pipeline/pending/";
var CHAT_PREFIX = "$:/temp/rimir/file-pipeline/chat/";
var SELECT_PREFIX = "$:/temp/rimir/file-pipeline/select/";
var SELECT_CHOICE = "$:/temp/rimir/file-pipeline/select-choice";
var INTERACTIVE_STATE = "$:/state/rimir/file-pipeline/interactive";
var SELECT_STATE = "$:/state/rimir/file-pipeline/select";

/*
Run a pipeline on a source file.

Options:
  uri        — canonical URI of the file
  pipeline   — pipeline name, or "auto" for MIME-type matching
  mimeType   — MIME type (used for auto-matching)
  sourceTitle — title of the source tiddler (for artifact creation)
  filename   — original filename (for prompt templates)
  onComplete — function(results) called when all steps (incl. LLM) are done
  onError    — function(error) called on failure
  onProgress — function(stepId, status) called per step
*/
exports.runPipeline = function(options) {
	var sourceTitle = options.sourceTitle;
	var uri = options.uri;
	var onComplete = options.onComplete || function() {};
	var onError = options.onError || function() {};
	var onProgress = options.onProgress || function() {};

	// Set status
	setStatus(sourceTitle, "Running pipeline...");

	// Call server route
	$tw.utils.httpRequest({
		url: "/api/file-pipeline",
		type: "POST",
		headers: {
			"Content-Type": "application/json",
			"x-requested-with": "TiddlyWiki"
		},
		data: JSON.stringify({
			uri: uri,
			pipeline: options.pipeline || "auto",
			mimeType: options.mimeType
		}),
		callback: function(err, responseText) {
			if(err) {
				setStatus(sourceTitle, "");
				onError(new Error("Pipeline request failed: " + err));
				return;
			}
			var data;
			try {
				data = JSON.parse(responseText);
			} catch(e) {
				setStatus(sourceTitle, "");
				onError(new Error("Invalid pipeline response"));
				return;
			}
			if(data.status === "error") {
				setStatus(sourceTitle, "");
				onError(new Error(data.error));
				return;
			}
			if(data.status === "disabled" || data.status === "no-match") {
				setStatus(sourceTitle, "");
				if(options.onServerDone) options.onServerDone();
				onComplete([]);
				return;
			}
			// Server-side processing done — signal caller before client-side steps
			if(options.onServerDone) options.onServerDone();
			processResults(sourceTitle, options, data.results || [], onComplete, onError, onProgress);
		}
	});
};

/*
Process server results: create artifacts for command steps, execute LLM steps.
*/
function processResults(sourceTitle, options, results, onComplete, onError, onProgress) {
	var extractedText = null;
	var allResults = [];

	function processStep(index) {
		if(index >= results.length) {
			setStatus(sourceTitle, "");
			onComplete(allResults);
			return;
		}
		var result = results[index];
		if(result.skipped || result.error) {
			allResults.push(result);
			processStep(index + 1);
			return;
		}
		onProgress(result.stepId, "processing");

		if(result.type === "llm") {
			// LLM step — execute client-side
			executeLlmStep(result.step, result.inputText, sourceTitle, options.filename, options.llmOptions, function(err, text) {
				if(err) {
					allResults.push({stepId: result.stepId, error: err.message});
					processStep(index + 1);
					return;
				}
				// Create artifact from LLM response
				createTextArtifact(sourceTitle, result.step.artifact, text);
				allResults.push({stepId: result.stepId, text: text, artifact: result.step.artifact});
				processStep(index + 1);
			}, function() {
				// Interactive mode pause — save remaining steps for resume
				savePendingState(sourceTitle, options, results, index, allResults);
			});
			return;
		}

		if(result.type === "select") {
			// Select step — show selection UI and pause pipeline
			if(!result.outputs || result.outputs.length === 0) {
				// No candidates (e.g., frame extraction failed or very short video) — skip
				allResults.push({stepId: result.stepId, skipped: true});
				processStep(index + 1);
				return;
			}
			setupSelectPanel(result.step, result.outputs, sourceTitle);
			savePendingState(sourceTitle, options, results, index, allResults);
			return;
		}

		// Command step — create artifacts from result
		if(result.text !== undefined) {
			// Captured stdout → text artifact
			createTextArtifact(sourceTitle, result.artifact, result.text);
			if(result.artifact && result.artifact.type === "extraction") {
				extractedText = result.text;
			}
		} else if(result.outputs) {
			// Multi-file output → multiple artifacts
			createMultiFileArtifacts(sourceTitle, result.artifact, result.outputs);
		} else if(result.uri) {
			// Single file output
			if(result.artifact && result.artifact.setField) {
				setFieldOnSource(sourceTitle, result.artifact.setField, result.uri);
			} else if(result.artifact && result.artifact.suffix) {
				createFileArtifact(sourceTitle, result.artifact, result.uri);
			}
		}

		allResults.push(result);
		processStep(index + 1);
	}

	processStep(0);
}

// --- Artifact creation ---

function createTextArtifact(sourceTitle, artifact, text) {
	if(!artifact || !artifact.suffix) return;
	var title = sourceTitle + artifact.suffix;
	var fields = {
		title: title,
		text: text,
		type: artifact.tiddlerType || "text/vnd.tiddlywiki",
		"_artifact_source": sourceTitle,
		"_artifact_type": artifact.type || "extraction"
	};
	// Legacy field for backward compat with llm-connect
	if(artifact.type === "extraction") {
		fields["extraction-source"] = sourceTitle;
		fields["extraction-date"] = new Date().toISOString();
	}
	$tw.wiki.addTiddler(new $tw.Tiddler(fields));
}

function createFileArtifact(sourceTitle, artifact, uri) {
	if(!artifact || !artifact.suffix) return;
	var title = sourceTitle + artifact.suffix;
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: title,
		text: "",
		type: artifact.tiddlerType || "application/octet-stream",
		_canonical_uri: uri,
		"_artifact_source": sourceTitle,
		"_artifact_type": artifact.type || "derived"
	}));
}

function createMultiFileArtifacts(sourceTitle, artifact, outputs) {
	if(!artifact || !artifact.prefix) return;
	for(var i = 0; i < outputs.length; i++) {
		var output = outputs[i];
		var title = sourceTitle + artifact.prefix + output.filename;
		$tw.wiki.addTiddler(new $tw.Tiddler({
			title: title,
			text: "",
			type: artifact.tiddlerType || "image/png",
			_canonical_uri: output.uri,
			"_artifact_source": sourceTitle,
			"_artifact_type": artifact.type || "derived"
		}));
	}
}

function setFieldOnSource(sourceTitle, fieldName, value) {
	var tiddler = $tw.wiki.getTiddler(sourceTitle);
	if(!tiddler) return;
	var update = {};
	update[fieldName] = value;
	$tw.wiki.addTiddler(new $tw.Tiddler(tiddler, update));
}

// --- LLM step execution ---

function executeLlmStep(step, inputText, sourceTitle, filename, llmOptions, callback, onPause) {
	var opts = llmOptions || {};
	var mode = step.mode || "auto";

	if(mode === "interactive") {
		// Interactive mode — set up chat and pause pipeline
		setupInteractiveChat(step, inputText, sourceTitle, filename);
		if(onPause) onPause();
		return;
	}

	// Auto mode — call orchestrator.runAction() programmatically
	setStatus(sourceTitle, "LLM processing: " + (step.id || "..."));

	var orchestrator, helpers;
	try {
		orchestrator = require("$:/plugins/rimir/llm-connect/orchestrator");
		helpers = require("$:/plugins/rimir/llm-connect/widget-helpers");
	} catch(e) {
		callback(new Error("llm-connect plugin required for LLM pipeline steps"));
		return;
	}

	// Priority: step field > dropzone prop-* > global default
	var provider = resolveConfigRef(step.provider) || opts.provider;
	var model = resolveConfigRef(step.model) || opts.model;
	var systemPrompt = resolveConfigRef(step.systemPrompt) || opts.systemPrompt;
	var config = helpers.resolveProviderConfig(provider, model, systemPrompt);
	var adapter = orchestrator.getAdapter(config.provider);
	var prompt = renderPromptTemplate(step.promptTemplate, {
		text: inputText,
		title: sourceTitle,
		filename: filename || ""
	});

	// Override max-tokens for pipeline LLM steps (default is often too low)
	if(step.maxTokens) {
		config.maxTokens = String(resolveConfigRef(step.maxTokens));
	} else if(!config.maxTokens || parseInt(config.maxTokens) < 8192) {
		config.maxTokens = "8192";
	}

	// Only send prompt (which already contains {{text}}), not contextText too
	orchestrator.runAction({
		prompt: prompt,
		config: config,
		adapter: adapter
	}).then(function(responseText) {
		callback(null, responseText);
	})["catch"](function(err) {
		callback(err);
	});
}

function setupInteractiveChat(step, inputText, sourceTitle, filename) {
	var prompt = renderPromptTemplate(step.promptTemplate, {
		text: inputText,
		title: sourceTitle,
		filename: filename || ""
	});

	var provider = resolveConfigRef(step.provider) || "";
	var model = resolveConfigRef(step.model) || "";

	// Create a chat tiddler with pre-loaded context
	var chatTitle = CHAT_PREFIX + encodeURIComponent(sourceTitle);
	var messages = [
		{role: "user", content: prompt}
	];

	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: chatTitle,
		text: "",
		tags: "$:/tags/rimir/llm-connect/chat",
		"llm-messages": JSON.stringify(messages),
		"llm-provider": provider,
		"llm-model": model,
		"fp-source-title": sourceTitle,
		"fp-step-id": step.id,
		"fp-artifact": JSON.stringify(step.artifact || {})
	}));

	// Signal interactive mode
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: INTERACTIVE_STATE,
		text: chatTitle
	}));
}

/*
Resume pipeline after interactive step completes.
Called from the interactive chat panel's "Use as artifact" button.
*/
exports.resumeInteractive = function(sourceTitle, responseText) {
	// Read pending state
	var pendingTitle = PENDING_PREFIX + encodeURIComponent(sourceTitle);
	var pendingTiddler = $tw.wiki.getTiddler(pendingTitle);
	if(!pendingTiddler) return;

	var pending;
	try {
		pending = JSON.parse(pendingTiddler.fields.text);
	} catch(e) { return; }

	// Create the artifact from the interactive step
	var step = pending.currentStep;
	if(step && step.artifact) {
		createTextArtifact(sourceTitle, step.artifact, responseText);
	}

	// Clean up interactive state
	$tw.wiki.deleteTiddler(INTERACTIVE_STATE);
	$tw.wiki.deleteTiddler(CHAT_PREFIX + encodeURIComponent(sourceTitle));
	$tw.wiki.deleteTiddler(pendingTitle);

	// Resume remaining steps
	var remaining = pending.remainingResults || [];
	var allResults = pending.completedResults || [];
	allResults.push({stepId: step ? step.id : "interactive", text: responseText});

	processResults(sourceTitle, pending.options || {}, remaining, function(results) {
		var combined = allResults.concat(results);
		if(pending.options && pending.options.onComplete) {
			pending.options.onComplete(combined);
		}
	}, function() {}, function() {});
};

function savePendingState(sourceTitle, options, results, currentIndex, completedResults) {
	var pendingTitle = PENDING_PREFIX + encodeURIComponent(sourceTitle);
	var currentStep = results[currentIndex] ? results[currentIndex].step : null;
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: pendingTitle,
		text: JSON.stringify({
			sourceTitle: sourceTitle,
			currentStep: currentStep,
			remainingResults: results.slice(currentIndex + 1),
			completedResults: completedResults,
			options: {
				uri: options.uri,
				pipeline: options.pipeline,
				mimeType: options.mimeType,
				sourceTitle: sourceTitle,
				filename: options.filename
			}
		}),
		type: "application/json"
	}));
}

// --- Utility exports ---

/*
Check if an extracted text cache exists for a title.
Returns the text string or null.
*/
exports.getExtractedText = function(title) {
	var cacheTitle = title + ".extracted";
	var tiddler = $tw.wiki.getTiddler(cacheTitle);
	if(!tiddler) return null;
	return tiddler.fields.text || null;
};

/*
Check if any pipeline can process the given MIME type.
Works browser-side by scanning pipeline tiddlers.
*/
exports.isExtractable = function(mimeType) {
	var TAG = "$:/tags/rimir/file-pipeline/pipeline";
	var titles = $tw.wiki.filterTiddlers("[all[tiddlers+shadows]tag[" + TAG + "]]");
	for(var i = 0; i < titles.length; i++) {
		var tiddler = $tw.wiki.getTiddler(titles[i]);
		if(!tiddler) continue;
		try {
			var def = JSON.parse(tiddler.fields.text);
			if(Array.isArray(def.match) && def.match.indexOf(mimeType) !== -1) {
				// Check if pipeline has a text extraction step
				for(var s = 0; s < (def.steps || []).length; s++) {
					if(def.steps[s].captureStdout && def.steps[s].artifact &&
					   def.steps[s].artifact.type === "extraction") {
						return true;
					}
				}
			}
		} catch(e) { /* skip */ }
	}
	return false;
};

// --- Select step ---

function setupSelectPanel(step, outputs, sourceTitle) {
	var selectTitle = SELECT_PREFIX + encodeURIComponent(sourceTitle);
	// Single JSON tiddler with all data (avoids multi-tiddler prefix issues)
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: selectTitle,
		type: "application/json",
		text: JSON.stringify({
			sourceTitle: sourceTitle,
			prompt: step.prompt || "Select image(s)",
			stepId: step.id,
			artifact: step.artifact || {},
			candidates: outputs.map(function(o) { return {uri: o.uri, filename: o.filename}; })
		})
	}));
	// Clear any previous choice
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: SELECT_CHOICE,
		text: ""
	}));
	// Signal UI
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: SELECT_STATE,
		text: selectTitle
	}));
}

/*
Resume pipeline after user confirms frame selection.
Called from handlers-startup.js via tm-fp-confirm-select.
*/
exports.resumeSelect = function(sourceTitle, selectedUri) {
	// Read pending state
	var pendingTitle = PENDING_PREFIX + encodeURIComponent(sourceTitle);
	var pendingTiddler = $tw.wiki.getTiddler(pendingTitle);
	if(!pendingTiddler) return;

	var pending;
	try {
		pending = JSON.parse(pendingTiddler.fields.text);
	} catch(e) { return; }

	var selectTitle = SELECT_PREFIX + encodeURIComponent(sourceTitle);
	var stepId = "select";
	try {
		var selectData = JSON.parse($tw.wiki.getTiddlerText(selectTitle) || "{}");
		stepId = selectData.stepId || stepId;
	} catch(e) {}

	// Clean up state tiddlers immediately (panel closes)
	cleanupSelectState(selectTitle);

	if(!selectedUri) {
		// User clicked "Skip" — no thumbnail, just resume
		$tw.wiki.deleteTiddler(pendingTitle);
		resumeRemaining(pending, [{stepId: stepId, skipped: true}]);
		return;
	}

	// Find source canonical URI for the finalize call
	var sourceTiddler = $tw.wiki.getTiddler(sourceTitle);
	var sourceUri = sourceTiddler ? sourceTiddler.fields._canonical_uri : "";
	if(!sourceUri) {
		$tw.wiki.deleteTiddler(pendingTitle);
		resumeRemaining(pending, [{stepId: stepId, error: "No _canonical_uri on source"}]);
		return;
	}

	// Call finalize route: resize frame → _generated/, clean up _derived/
	setStatus(sourceTitle, "Finalizing thumbnail...");
	$tw.utils.httpRequest({
		url: "/api/file-pipeline-finalize",
		type: "POST",
		headers: {"Content-Type": "application/json", "x-requested-with": "TiddlyWiki"},
		data: JSON.stringify({sourceUri: sourceUri, frameUri: selectedUri}),
		callback: function(err, responseText) {
			setStatus(sourceTitle, "");
			if(err) {
				console.warn("file-pipeline finalize error:", err);
				// Fallback: use raw frame URI as thumbnail
				setFieldOnSource(sourceTitle, "_thumbnail_uri", selectedUri);
			} else {
				try {
					var result = JSON.parse(responseText);
					if(result.thumbnailUri) {
						setFieldOnSource(sourceTitle, "_thumbnail_uri", result.thumbnailUri);
					} else {
						setFieldOnSource(sourceTitle, "_thumbnail_uri", selectedUri);
					}
				} catch(e) {
					setFieldOnSource(sourceTitle, "_thumbnail_uri", selectedUri);
				}
			}
			$tw.wiki.deleteTiddler(pendingTitle);
			resumeRemaining(pending, [{stepId: stepId, selectedUri: selectedUri}]);
		}
	});
};

function resumeRemaining(pending, completedSteps) {
	var remaining = pending.remainingResults || [];
	var allResults = (pending.completedResults || []).concat(completedSteps);
	processResults(pending.sourceTitle || "", pending.options || {}, remaining, function(results) {
		var combined = allResults.concat(results);
		if(pending.options && pending.options.onComplete) {
			pending.options.onComplete(combined);
		}
	}, function() {}, function() {});
}

/*
Cancel select — clean up state without creating artifacts.
*/
exports.cancelSelect = function(sourceTitle) {
	var selectTitle = SELECT_PREFIX + encodeURIComponent(sourceTitle);
	var pendingTitle = PENDING_PREFIX + encodeURIComponent(sourceTitle);
	cleanupSelectState(selectTitle);
	$tw.wiki.deleteTiddler(pendingTitle);
	setStatus(sourceTitle, "");
	// Clean up derived frames from disk
	var sourceTiddler = $tw.wiki.getTiddler(sourceTitle);
	var sourceUri = sourceTiddler ? sourceTiddler.fields._canonical_uri : "";
	if(sourceUri) {
		$tw.utils.httpRequest({
			url: "/api/file-pipeline-finalize",
			type: "POST",
			headers: {"Content-Type": "application/json", "x-requested-with": "TiddlyWiki"},
			data: JSON.stringify({sourceUri: sourceUri, frameUri: null}),
			callback: function() {}
		});
	}
};

function cleanupSelectState(selectTitle) {
	$tw.wiki.deleteTiddler(SELECT_STATE);
	$tw.wiki.deleteTiddler(selectTitle);
	$tw.wiki.deleteTiddler(SELECT_CHOICE);
}

// --- Helpers ---

function setStatus(sourceTitle, text) {
	$tw.wiki.addTiddler(new $tw.Tiddler({
		title: STATUS_PREFIX + encodeURIComponent(sourceTitle),
		text: text
	}));
}

function resolveConfigRef(value) {
	if(typeof value !== "string") return value;
	var match = value.match(/^\{\{config:(.+)\}\}$/);
	if(!match) return value;
	var tiddler = $tw.wiki.getTiddler(match[1]);
	return (tiddler && tiddler.fields.text || "").trim();
}

function renderPromptTemplate(templateTitle, vars) {
	if(!templateTitle) return vars.text || "";
	var tiddler = $tw.wiki.getTiddler(templateTitle);
	if(!tiddler) return vars.text || "";
	var text = tiddler.fields.text || "";
	return text
		.split("{{text}}").join(vars.text || "")
		.split("{{title}}").join(vars.title || "")
		.split("{{filename}}").join(vars.filename || "");
}
","type":"application/javascript","module-type":"library"},"$:/plugins/rimir/file-pipeline/pipeline-executor":{"title":"$:/plugins/rimir/file-pipeline/pipeline-executor","text":"/*\
title: $:/plugins/rimir/file-pipeline/pipeline-executor
type: application/javascript
module-type: library

Server-side pipeline executor. Loads pipeline definitions from tagged tiddlers,
matches pipelines by MIME type, and runs command steps sequentially.
LLM steps are returned as markers for client-side execution.

\*/
"use strict";

var child_process = require("child_process");
var fs = require("fs");
var path = require("path");

var PIPELINE_TAG = "$:/tags/rimir/file-pipeline/pipeline";

var _cachedPipelines = null;
var _cachedActions = null;

var logger = new $tw.utils.Logger("file-pipeline", {colour: "magenta"});

// --- Pipeline loading ---

function loadPipelines() {
	var titles = $tw.wiki.filterTiddlers("[all[tiddlers+shadows]tag[" + PIPELINE_TAG + "]]");
	var pipelines = [];
	for(var i = 0; i < titles.length; i++) {
		var tiddler = $tw.wiki.getTiddler(titles[i]);
		if(!tiddler) continue;
		try {
			var def = JSON.parse(tiddler.fields.text);
			if(def.name && Array.isArray(def.steps)) {
				def._title = titles[i];
				pipelines.push(def);
			}
		} catch(e) {
			logger.log("Failed to parse pipeline " + titles[i] + ": " + e.message);
		}
	}
	_cachedPipelines = pipelines;
	return pipelines;
}

exports.loadPipelines = loadPipelines;

exports.invalidate = function() {
	_cachedPipelines = null;
	_cachedActions = null;
};

exports.matchPipeline = function(mimeType) {
	var pipelines = _cachedPipelines || loadPipelines();
	for(var i = 0; i < pipelines.length; i++) {
		if(Array.isArray(pipelines[i].match) && pipelines[i].match.indexOf(mimeType) !== -1) {
			return pipelines[i];
		}
	}
	return null;
};

exports.getPipeline = function(name) {
	var pipelines = _cachedPipelines || loadPipelines();
	for(var i = 0; i < pipelines.length; i++) {
		if(pipelines[i].name === name) {
			return pipelines[i];
		}
	}
	return null;
};

// --- runner-actions.json loading ---

function loadActions() {
	if(_cachedActions) return _cachedActions;
	// Start with built-in defaults from config tiddler
	var defaults = {};
	var defaultsTiddler = $tw.wiki.getTiddler("$:/config/rimir/file-pipeline/default-actions");
	if(defaultsTiddler && defaultsTiddler.fields.text) {
		try { defaults = JSON.parse(defaultsTiddler.fields.text); } catch(e) {}
	}
	// Merge with runner-actions.json (user overrides take precedence)
	var userActions = {};
	var actionsPath = path.resolve($tw.boot.wikiPath, "runner-actions.json");
	try {
		userActions = JSON.parse(fs.readFileSync(actionsPath, "utf8"));
	} catch(e) {
		// No runner-actions.json — use defaults only
	}
	_cachedActions = {};
	for(var key in defaults) { _cachedActions[key] = defaults[key]; }
	for(var key2 in userActions) { _cachedActions[key2] = userActions[key2]; }
	return _cachedActions;
}

// --- Template resolution ---

function resolveTemplate(template, vars) {
	if(!template) return template;
	return template
		.split("{{name}}").join(vars.name || "")
		.split("{{basename}}").join(vars.basename || "")
		.split("{{ext}}").join(vars.ext || "");
}

function resolveConfigRef(value) {
	if(typeof value !== "string") return value;
	var match = value.match(/^\{\{config:(.+)\}\}$/);
	if(!match) return value;
	var tiddler = $tw.wiki.getTiddler(match[1]);
	return (tiddler && tiddler.fields.text || "").trim();
}

function checkCondition(condition) {
	if(!condition) return true;
	var configTitle = condition.config;
	var expectedValue = condition.equals;
	if(!configTitle) return true;
	var tiddler = $tw.wiki.getTiddler(configTitle);
	var actual = (tiddler && tiddler.fields.text || "").trim();
	return actual === expectedValue;
}

// --- Step execution ---

function resolveInput(step, sourcePath, stepResults) {
	if(!step.input || step.input === "source") {
		return sourcePath;
	}
	var ref = step.input.match(/^step:(.+)$/);
	if(ref && stepResults[ref[1]]) {
		var prev = stepResults[ref[1]];
		// For captureStdout steps, there's no output file path
		if(prev.outputPath) return prev.outputPath;
		// Fallback to source if previous step had no file output
		return sourcePath;
	}
	return sourcePath;
}

function buildOutputPath(step, inputPath, sourceDir) {
	if(!step.output) return null;
	var parsed = path.parse(inputPath);
	var vars = {
		name: parsed.name,
		basename: parsed.base,
		ext: parsed.ext
	};
	var relOutput = resolveTemplate(step.output, vars);
	return path.resolve(sourceDir, relOutput);
}

// Some commands (e.g., libreoffice --outdir) write to a directory but the actual
// output file has a different path than what's passed as {{output}}.
// `outputFile` tells the executor where the real result ends up.
function buildOutputFilePath(step, inputPath, sourceDir) {
	if(!step.outputFile) return null;
	var parsed = path.parse(inputPath);
	var vars = {
		name: parsed.name,
		basename: parsed.base,
		ext: parsed.ext
	};
	var relOutput = resolveTemplate(step.outputFile, vars);
	return path.resolve(sourceDir, relOutput);
}

function buildOutputUri(outputPath, canonicalUri, basePath) {
	// Derive the output URI relative to basePath, using the same URI prefix as canonicalUri
	var relToBase = path.relative(basePath, outputPath).replace(/\\/g, "/");
	// Find the URI prefix from canonicalUri: everything before the first path component that matches basePath content
	var uriParts = canonicalUri.split("/");
	var relParts = relToBase.split("/");
	// Walk backwards from canonicalUri to find where basePath maps to
	// Simpler: just use the base directory of canonicalUri's parent
	var uriDir = canonicalUri.substring(0, canonicalUri.lastIndexOf("/"));
	// But output might be in a subdirectory relative to the source file
	// So we compute relative from source file's directory
	var sourceFileDir = path.dirname(path.resolve(basePath, canonicalUri.split("/").slice(1).join("/")));
	// Actually, let's just compute from basePath
	var locationPrefix = canonicalUri.substring(0, canonicalUri.indexOf("/", 1) + 1);
	// For URIs like /files/pdf/report.pdf, prefix = /files/
	// relToBase = pdf/_generated/report_thumb.png
	// result = /files/pdf/_generated/report_thumb.png
	return locationPrefix + relToBase;
}

function executeCommand(step, inputPath, outputPath, callback) {
	var actions = loadActions();
	var actionDef = actions[step.action];
	if(!actionDef || !actionDef.command) {
		logger.log("Runner action not found: " + step.action);
		callback(new Error("Runner action not found: " + step.action));
		return;
	}
	// Create output directory if needed
	if(outputPath) {
		// If outputPath ends with / it IS a directory (e.g., libreoffice --outdir)
		if(outputPath.charAt(outputPath.length - 1) === "/" || outputPath.charAt(outputPath.length - 1) === "\\") {
			$tw.utils.createDirectory(outputPath);
		} else {
			$tw.utils.createDirectory(path.dirname(outputPath));
		}
	}
	// Build command from template
	var command = actionDef.command;
	command = command.split("{{input}}").join('"' + inputPath + '"');
	if(outputPath) {
		command = command.split("{{output}}").join('"' + outputPath + '"');
	}
	// Resolve params
	if(step.params) {
		for(var key in step.params) {
			var val = resolveConfigRef(step.params[key]);
			// Normalize resolution (e.g., "200" → "200x200")
			if(key === "resolution" && /^\d+$/.test(val)) {
				val = val + "x" + val;
			}
			command = command.split("{{" + key + "}}").join(val);
		}
	}
	// Per-step timeout: step.timeout (seconds) > default 5min, 0 = no timeout
	var timeoutMs = step.timeout !== undefined ? parseInt(step.timeout) * 1000 : 300000;
	logger.log("Executing: " + command);
	child_process.exec(command, {
		cwd: $tw.boot.wikiPath,
		maxBuffer: 10 * 1024 * 1024,
		timeout: timeoutMs
	}, function(err, stdout, stderr) {
		if(err) {
			logger.log("Step '" + step.id + "' failed: " + err.message);
			if(stderr) logger.log("stderr: " + stderr);
			callback(err);
			return;
		}
		callback(null, stdout || "");
	});
}

var DEFAULT_SCAN_EXTENSIONS = [".png", ".jpg", ".jpeg", ".gif", ".webp"];

function scanDirectory(dirPath, extensions) {
	var allowedExts = extensions || DEFAULT_SCAN_EXTENSIONS;
	var outputs = [];
	try {
		var files = fs.readdirSync(dirPath);
		for(var i = 0; i < files.length; i++) {
			var ext = path.extname(files[i]).toLowerCase();
			if(allowedExts.indexOf(ext) !== -1) {
				outputs.push({
					filename: files[i],
					filePath: path.join(dirPath, files[i])
				});
			}
		}
	} catch(e) {
		logger.log("scanDir failed: " + e.message);
	}
	return outputs;
}

// --- Main pipeline runner ---

/*
Run a pipeline definition against a file.

Parameters:
  def         — pipeline definition object (from tiddler JSON)
  inputPath   — absolute filesystem path of the source file
  canonicalUri — the source file's canonical URI (e.g., /files/pdf/report.pdf)
  basePath    — absolute filesystem path of the location's basePath
  callback    — function(err, results) where results is an array of step results

Each result in the array:
  { stepId, skipped: true }                                  — condition not met
  { stepId, type: "llm", step: <stepDef>, inputText: "..." } — LLM marker for client
  { stepId, type: "select", step: <stepDef>, outputs: [...] } — select marker for client
  { stepId, uri, outputPath, artifact }                      — single file output
  { stepId, text, artifact }                                 — captured stdout text
  { stepId, outputs: [{filename, uri, filePath}], artifact } — multi-file output (scanDir)
*/
exports.runPipeline = function(def, inputPath, canonicalUri, basePath, callback) {
	var steps = def.steps || [];
	var stepResults = {}; // id → result
	var allResults = [];
	var sourceDir = path.dirname(inputPath);
	var uriDir = canonicalUri.substring(0, canonicalUri.lastIndexOf("/"));

	function runStep(index) {
		if(index >= steps.length) {
			callback(null, allResults);
			return;
		}
		var step = steps[index];
		var stepType = step.type || "command";

		// Check condition
		if(!checkCondition(step.condition)) {
			var skipped = {stepId: step.id, skipped: true};
			stepResults[step.id] = skipped;
			allResults.push(skipped);
			runStep(index + 1);
			return;
		}

		// Select steps are client-side — return marker with candidate outputs from referenced step
		if(stepType === "select") {
			var selectRef = (step.input || "").match(/^step:(.+)$/);
			var candidateOutputs = [];
			if(selectRef && stepResults[selectRef[1]] && stepResults[selectRef[1]].outputs) {
				candidateOutputs = stepResults[selectRef[1]].outputs;
			}
			var selectMarker = {
				stepId: step.id,
				type: "select",
				step: step,
				outputs: candidateOutputs
			};
			stepResults[step.id] = selectMarker;
			allResults.push(selectMarker);
			runStep(index + 1);
			return;
		}

		// LLM steps are client-side — return marker
		if(stepType === "llm") {
			var llmInputPath = resolveInput(step, inputPath, stepResults);
			var inputText = "";
			// If input references a captureStdout step, use its text
			var inputRef = (step.input || "").match(/^step:(.+)$/);
			if(inputRef && stepResults[inputRef[1]] && stepResults[inputRef[1]].text) {
				inputText = stepResults[inputRef[1]].text;
			}
			var marker = {
				stepId: step.id,
				type: "llm",
				step: step,
				inputText: inputText
			};
			stepResults[step.id] = marker;
			allResults.push(marker);
			runStep(index + 1);
			return;
		}

		// Command step
		var stepInput = resolveInput(step, inputPath, stepResults);
		var outputPath = buildOutputPath(step, stepInput, sourceDir);
		var outputFilePath = buildOutputFilePath(step, stepInput, sourceDir);

		executeCommand(step, stepInput, outputPath, function(err, stdout) {
			if(err) {
				// Step failed — skip but continue pipeline
				var errResult = {stepId: step.id, error: err.message};
				stepResults[step.id] = errResult;
				allResults.push(errResult);
				runStep(index + 1);
				return;
			}

			var result = {stepId: step.id, artifact: step.artifact};

			if(step.captureStdout) {
				// Text output from stdout
				var maxSize = parseInt(resolveConfigRef("{{config:$:/config/rimir/file-pipeline/max-extraction-size}}")) || 500000;
				var text = stdout;
				if(text.length > maxSize) {
					text = text.substring(0, maxSize) + "\n\n... [extraction truncated at " + maxSize + " chars]";
				}
				result.text = text;
			} else if(step.scanDir && outputPath) {
				// Multiple output files — scan the output directory, but only pick up
				// files matching the resolved output basename prefix. Without this,
				// a shared scan directory (e.g. `_generated/`) would leak files from
				// previous sources into this step's results.
				var scanPath = path.dirname(outputPath);
				var outputBasename = path.basename(outputPath);
				var files = scanDirectory(scanPath, step.scanExtensions);
				result.outputs = [];
				for(var f = 0; f < files.length; f++) {
					if(files[f].filename.indexOf(outputBasename) !== 0) continue;
					var relToSource = path.relative(sourceDir, files[f].filePath).replace(/\\/g, "/");
					result.outputs.push({
						filename: files[f].filename,
						uri: uriDir + "/" + relToSource,
						filePath: files[f].filePath
					});
				}
			} else if(outputPath) {
				// Single file output — use outputFilePath for the actual result if available
				var actualOutput = outputFilePath || outputPath;
				var relToSource = path.relative(sourceDir, actualOutput).replace(/\\/g, "/");
				result.uri = uriDir + "/" + relToSource;
				result.outputPath = actualOutput;
			}

			stepResults[step.id] = result;
			allResults.push(result);
			runStep(index + 1);
		});
	}

	runStep(0);
};
