  ]
}"},"$:/plugins/rimir/file-pipeline/pipelines/xlsx":{"title":"$:/plugins/rimir/file-pipeline/pipelines/xlsx","tags":"$:/tags/rimir/file-pipeline/pipeline","type":"application/json","text":"{
